INSERT INTO public.cities (id, slug, name, country, country_code, continent, photo, lat, lng, score_family, score_child_safety, score_school_access, score_nature, score_internet, score_healthcare, cost_family_monthly, cost_rent_2br, cost_international_school, cost_local_school, cost_childcare, families_now, families_been, return_rate, best_months, timezone, languages, homeschool_legal, visa_friendly, kids_age_ideal, tags, description, data_confidence) VALUES ('43', 'crete', 'Crete', 'Greece', 'GR', 'Europe', 'https://images.unsplash.com/photo-1570077188670-e3a8d69ac5ff?w=800&h=500&fit=crop', 35.2401, 24.4709, 78, 84, 50, 92, 65, 65, 2400, 900, 0, 0, 200, 8, 100, 52, ARRAY['May','June','September','October'], 'Europe/Athens', ARRAY['Greek','English'], 'Yes (grey area)', 'OK', 'Young children', ARRAY['beach','nature','mountains','safe','warm','mediterranean'], 'Crete is Greece''s largest island with mountains, gorges, and beaches that rival the Caribbean. No international schools — this is a homeschool family destination where kids live outdoors.', 70) ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.cities (id, slug, name, country, country_code, continent, photo, lat, lng, score_family, score_child_safety, score_school_access, score_nature, score_internet, score_healthcare, cost_family_monthly, cost_rent_2br, cost_international_school, cost_local_school, cost_childcare, families_now, families_been, return_rate, best_months, timezone, languages, homeschool_legal, visa_friendly, kids_age_ideal, tags, description, data_confidence) VALUES ('44', 'ho-chi-minh', 'Ho Chi Minh City', 'Vietnam', 'VN', 'Asia', 'https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&h=500&fit=crop', 10.8231, 106.6297, 77, 68, 78, 50, 82, 68, 2000, 650, 500, 50, 180, 18, 230, 55, ARRAY['December','January','February','March'], 'Asia/Ho_Chi_Minh', ARRAY['Vietnamese','English'], 'Yes (grey area)', 'Good', 'All ages', ARRAY['low cost','international schools','expat community','warm','tropical'], 'Saigon is Vietnam''s economic engine with a massive international school ecosystem and one of the world''s best street food scenes. Chaotic but thrilling — families either love it or move to Da Nang.', 70) ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.cities (id, slug, name, country, country_code, continent, photo, lat, lng, score_family, score_child_safety, score_school_access, score_nature, score_internet, score_healthcare, cost_family_monthly, cost_rent_2br, cost_international_school, cost_local_school, cost_childcare, families_now, families_been, return_rate, best_months, timezone, languages, homeschool_legal, visa_friendly, kids_age_ideal, tags, description, data_confidence) VALUES ('45', 'funchal', 'Funchal', 'Portugal', 'PT', 'Europe', 'https://images.unsplash.com/photo-1588880331179-bc9b93a8cb5e?w=800&h=500&fit=crop', 32.6669, -16.9241, 79, 86, 55, 90, 75, 72, 2400, 1000, 400, 0, 250, 10, 120, 58, ARRAY['April','May','June','September','October'], 'Atlantic/Madeira', ARRAY['Portuguese','English'], 'Yes (grey area)', 'Excellent', 'All ages', ARRAY['nature','mountains','safe','warm','beach','mediterranean'], 'Funchal is Madeira''s capital — a subtropical island with levada walks, year-round mild weather, and Portuguese visa advantages. Quieter than the mainland, with a growing remote family community.', 70) ON CONFLICT (slug) DO NOTHING;